previewCss:
@keyframes darma-loader-uiverse-chromatic-text-glow-chromaticHue {
  0%, 100% { filter: hue-rotate(0deg); }
  50% { filter: hue-rotate(360deg); }
}
.darma-loader-uiverse-chromatic-text-glow {
  font-size: 30px;
  line-height: 1;
  background: linear-gradient(to right, var(--loader-color, #2d60ec), var(--loader-secondary-color, #3ccfda));
  -webkit-text-fill-color: transparent;
  -webkit-background-clip: text;
  background-clip: text;
  animation: darma-loader-uiverse-chromatic-text-glow-chromaticHue 9s linear infinite;
  font-weight: 800;
}

